1	<?php
2	
3	namespace Illuminate\Events;
4	
5	use Illuminate\Bus\Queueable;
6	use Illuminate\Container\Container;
7	use Illuminate\Contracts\Cache\Repository as Cache;
8	use Illuminate\Contracts\Queue\Job;
9	use Illuminate\Contracts\Queue\ShouldQueue;
10	use Illuminate\Queue\InteractsWithQueue;
11	
12	class CallQueuedListener implements ShouldQueue
13	{
14	    use InteractsWithQueue, Queueable;
15	
16	    /**
17	     * The listener class name.
18	     *
19	     * @var class-string
20	     */
21	    public $class;
22	
23	    /**
24	     * The listener method.
25	     *
26	     * @var string
27	     */
28	    public $method;
29	
30	    /**
31	     * The data to be passed to the listener.
32	     *
33	     * @var array
34	     */
35	    public $data;
36	
37	    /**
38	     * The number of times the job may be attempted.
39	     *
40	     * @var int
41	     */
42	    public $tries;
43	
44	    /**
45	     * The maximum number of exceptions allowed, regardless of attempts.
46	     *
47	     * @var int
48	     */
49	    public $maxExceptions;
50	
51	    /**
52	     * The number of seconds to wait before retrying a job that encountered an uncaught exception.
53	     *
54	     * @var int
55	     */
56	    public $backoff;
57	
58	    /**
59	     * The timestamp indicating when the job should timeout.
60	     *
61	     * @var int
62	     */
63	    public $retryUntil;
64	
65	    /**
66	     * The number of seconds the job can run before timing out.
67	     *
68	     * @var int
69	     */
70	    public $timeout;
71	
72	    /**
73	     * Indicates if the job should fail if the timeout is exceeded.
74	     *
75	     * @var bool
76	     */
77	    public $failOnTimeout = false;
78	
79	    /**
80	     * Indicates if the job should be encrypted.
81	     *
82	     * @var bool
83	     */
84	    public $shouldBeEncrypted = false;
85	
86	    /**
87	     * Indicates if the job should be deleted when models are missing.
88	     *
89	     * @var bool
90	     */
91	    public $deleteWhenMissingModels;
92	
93	    /**
94	     * Indicates if the listener should be unique.
95	     */
96	    public bool $shouldBeUnique = false;
97	
98	    /**
99	     * Indicates if the listener should be unique until processing begins.
100	     */
101	    public bool $shouldBeUniqueUntilProcessing = false;
102	
103	    /**
104	     * The unique ID of the listener.
105	     */
106	    public mixed $uniqueId = null;
107	
108	    /**
109	     * The number of seconds the unique lock should be maintained.
110	     */
111	    public ?int $uniqueFor = null;
112	
113	    /**
114	     * Create a new job instance.
115	     *
116	     * @param  class-string  $class
117	     * @param  string  $method
118	     * @param  array  $data
119	     */
120	    public function __construct($class, $method, $data)
121	    {
122	        $this->data = $data;
123	        $this->class = $class;
124	        $this->method = $method;
125	    }
126	
127	    /**
128	     * Handle the queued job.
129	     *
130	     * @param  \Illuminate\Container\Container  $container
131	     * @return void
132	     */
133	    public function handle(Container $container)
134	    {
135	        $this->prepareData();
136	
137	        $handler = $this->setJobInstanceIfNecessary(
138	            $this->job, $container->make($this->class)
139	        );
140	
141	        $handler->{$this->method}(...array_values($this->data));
142	    }
143	
144	    /**
145	     * Determine if the listener should be unique.
146	     */
147	    public function shouldBeUnique(): bool
148	    {
149	        return $this->shouldBeUnique;
150	    }
151	
152	    /**
153	     * Determine if the listener should be unique until processing begins.
154	     */
155	    public function shouldBeUniqueUntilProcessing(): bool
156	    {
157	        return $this->shouldBeUniqueUntilProcessing;
158	    }
159	
160	    /**
161	     * Get the unique ID for the listener.
162	     */
163	    public function uniqueId(): mixed
164	    {
165	        return $this->uniqueId;
166	    }
167	
168	    /**
169	     * Get the number of seconds the unique lock should be maintained.
170	     */
171	    public function uniqueFor(): ?int
172	    {
173	        return $this->uniqueFor;
174	    }
175	
176	    /**
177	     * Get the cache store used to manage unique locks.
178	     */
179	    public function uniqueVia(): ?Cache
180	    {
181	        $listener = Container::getInstance()->make($this->class);
182	
183	        if (! method_exists($listener, 'uniqueVia')) {
184	            return null;
185	        }
186	
187	        $this->prepareData();
188	
189	        return $listener->uniqueVia(...array_values($this->data));
190	    }
191	
192	    /**
193	     * Set the job instance of the given class if necessary.
194	     *
195	     * @param  \Illuminate\Contracts\Queue\Job  $job
196	     * @param  object  $instance
197	     * @return object
198	     */
199	    protected function setJobInstanceIfNecessary(Job $job, $instance)
200	    {
201	        if (isset(class_uses_recursive($instance)[InteractsWithQueue::class])) {
202	            $instance->setJob($job);
203	        }
204	
205	        return $instance;
206	    }
207	
208	    /**
209	     * Call the failed method on the job instance.
210	     *
211	     * The event instance and the exception will be passed.
212	     *
213	     * @param  \Throwable  $e
214	     * @return void
215	     */
216	    public function failed($e)
217	    {
218	        $this->prepareData();
219	
220	        $handler = Container::getInstance()->make($this->class);
221	
222	        $parameters = array_merge(array_values($this->data), [$e]);
223	
224	        if (method_exists($handler, 'failed')) {
225	            $handler->failed(...$parameters);
226	        }
227	    }
228	
229	    /**
230	     * Unserialize the data if needed.
231	     *
232	     * @return void
233	     */
234	    protected function prepareData()
235	    {
236	        if (is_string($this->data)) {
237	            $this->data = unserialize($this->data);
238	        }
239	    }
240	
241	    /**
242	     * Get the display name for the queued job.
243	     *
244	     * @return string
245	     */
246	    public function displayName()
247	    {
248	        return $this->class;
249	    }
250	
251	    /**
252	     * Prepare the instance for cloning.
253	     *
254	     * @return void
255	     */
256	    public function __clone()
257	    {
258	        $this->data = array_map(function ($data) {
259	            return is_object($data) ? clone $data : $data;
260	        }, $this->data);
261	    }
262	}
