2	
3	namespace Illuminate\Events;
4	
5	use Closure;
6	use Exception;
7	use Illuminate\Bus\UniqueLock;
8	use Illuminate\Container\Container;
9	use Illuminate\Contracts\Broadcasting\Factory as BroadcastFactory;
10	use Illuminate\Contracts\Broadcasting\ShouldBroadcast;
11	use Illuminate\Contracts\Cache\Repository as Cache;
12	use Illuminate\Contracts\Container\Container as ContainerContract;
13	use Illuminate\Contracts\Events\Dispatcher as DispatcherContract;
14	use Illuminate\Contracts\Events\ShouldDispatchAfterCommit;
15	use Illuminate\Contracts\Events\ShouldHandleEventsAfterCommit;
16	use Illuminate\Contracts\Queue\ShouldBeEncrypted;
17	use Illuminate\Contracts\Queue\ShouldBeUnique;
18	use Illuminate\Contracts\Queue\ShouldBeUniqueUntilProcessing;
19	use Illuminate\Contracts\Queue\ShouldQueue;
20	use Illuminate\Contracts\Queue\ShouldQueueAfterCommit;
21	use Illuminate\Queue\Attributes\Backoff;
22	use Illuminate\Queue\Attributes\Connection;
23	use Illuminate\Queue\Attributes\Delay;
24	use Illuminate\Queue\Attributes\DeleteWhenMissingModels;
25	use Illuminate\Queue\Attributes\FailOnTimeout;
26	use Illuminate\Queue\Attributes\MaxExceptions;
27	use Illuminate\Queue\Attributes\Queue as QueueAttribute;
28	use Illuminate\Queue\Attributes\Timeout;
29	use Illuminate\Queue\Attributes\Tries;
30	use Illuminate\Queue\Attributes\UniqueFor;
31	use Illuminate\Support\Arr;
32	use Illuminate\Support\Collection;
33	use Illuminate\Support\Queue\Concerns\ResolvesQueueRoutes;
34	use Illuminate\Support\Str;
35	use Illuminate\Support\Traits\Macroable;
36	use Illuminate\Support\Traits\ReadsClassAttributes;
37	use Illuminate\Support\Traits\ReflectsClosures;
38	use ReflectionClass;
39	
40	use function Illuminate\Support\enum_value;
41	
42	class Dispatcher implements DispatcherContract
43	{
44	    use Macroable, ReadsClassAttributes, ReflectsClosures, ResolvesQueueRoutes;
45	
46	    /**
47	     * The IoC container instance.
48	     *
49	     * @var \Illuminate\Contracts\Container\Container
50	     */
51	    protected $container;
52	
53	    /**
54	     * The registered event listeners.
55	     *
56	     * @var array<string, callable|array|class-string|null>
57	     */
58	    protected $listeners = [];
59	
60	    /**
61	     * The wildcard listeners.
62	     *
63	     * @var array<string, \Closure|string>
64	     */
65	    protected $wildcards = [];
66	
67	    /**
68	     * The cached wildcard listeners.
69	     *
70	     * @var array<string, \Closure|string>
71	     */
72	    protected $wildcardsCache = [];
73	
74	    /**
75	     * The queue resolver instance.
76	     *
77	     * @var callable(): \Illuminate\Contracts\Queue\Queue
78	     */
79	    protected $queueResolver;
80	
81	    /**
82	     * The database transaction manager resolver instance.
83	     *
84	     * @var callable
85	     */
86	    protected $transactionManagerResolver;
87	
88	    /**
89	     * The currently deferred events.
90	     *
91	     * @var array
92	     */
93	    protected $deferredEvents = [];
94	
95	    /**
96	     * Indicates if events should be deferred.
97	     *
98	     * @var bool
99	     */
100	    protected $deferringEvents = false;
101	
102	    /**
103	     * The specific events to defer (null means defer all events).
104	     *
105	     * @var string[]|null
106	     */
107	    protected $eventsToDefer = null;
108	
109	    /**
110	     * Create a new event dispatcher instance.
111	     */
112	    public function __construct(?ContainerContract $container = null)
113	    {
114	        $this->container = $container ?: new Container;
115	    }
116	
117	    /**
118	     * Register an event listener with the dispatcher.
119	     *
120	     * @param  \Illuminate\Events\QueuedClosure|callable|array|class-string|string  $events
121	     * @param  \Illuminate\Events\QueuedClosure|callable|array|class-string|null  $listener
122	     * @return void
123	     */
124	    public function listen($events, $listener = null)
125	    {
126	        if ($events instanceof Closure) {
127	            return (new Collection($this->firstClosureParameterTypes($events)))
128	                ->each(function ($event) use ($events) {
129	                    $this->listen($event, $events);
130	                });
131	        } elseif ($events instanceof QueuedClosure) {
132	            return (new Collection($this->firstClosureParameterTypes($events->closure)))
133	                ->each(function ($event) use ($events) {
134	                    $this->listen($event, $events->resolve());
135	                });
136	        } elseif ($listener instanceof QueuedClosure) {
137	            $listener = $listener->resolve();
138	        }
139	
140	        foreach ((array) $events as $event) {
141	            if (str_contains($event, '*')) {
142	                $this->setupWildcardListen($event, $listener);
143	            } else {
144	                $this->listeners[$event][] = $listener;
145	            }
146	        }
147	    }
148	
149	    /**
150	     * Setup a wildcard listener callback.
151	     *
152	     * @param  string  $event
153	     * @param  \Closure|string  $listener
154	     * @return void
155	     */
156	    protected function setupWildcardListen($event, $listener)
157	    {
158	        $this->wildcards[$event][] = $listener;
159	
160	        $this->wildcardsCache = [];
161	    }
162	
163	    /**
164	     * Determine if a given event has listeners.
165	     *
166	     * @param  string  $eventName
167	     * @return bool
168	     */
169	    public function hasListeners($eventName)
170	    {
171	        return isset($this->listeners[$eventName]) ||
172	               isset($this->wildcards[$eventName]) ||
173	               $this->hasWildcardListeners($eventName);
174	    }
175	
176	    /**
177	     * Determine if the given event has any wildcard listeners.
178	     *
179	     * @param  string  $eventName
180	     * @return bool
181	     */
182	    public function hasWildcardListeners($eventName)
183	    {
184	        foreach ($this->wildcards as $key => $listeners) {
185	            if (Str::is($key, $eventName)) {
186	                return true;
187	            }
188	        }
189	
190	        return false;
191	    }
192	
193	    /**
194	     * Register an event and payload to be fired later.
195	     *
196	     * @param  string  $event
197	     * @param  object|array  $payload
198	     * @return void
199	     */
200	    public function push($event, $payload = [])
201	    {
202	        $this->listen($event.'_pushed', function () use ($event, $payload) {
203	            $this->dispatch($event, $payload);
204	        });
205	    }
206	
207	    /**
208	     * Flush a set of pushed events.
209	     *
210	     * @param  string  $event
211	     * @return void
212	     */
213	    public function flush($event)
214	    {
215	        $this->dispatch($event.'_pushed');
216	    }
217	
218	    /**
219	     * Register an event subscriber with the dispatcher.
220	     *
221	     * @param  object|string  $subscriber
222	     * @return void
223	     */
224	    public function subscribe($subscriber)
225	    {
226	        $subscriber = $this->resolveSubscriber($subscriber);
227	
228	        $events = $subscriber->subscribe($this);
229	
230	        if (is_array($events)) {
231	            foreach ($events as $event => $listeners) {
232	                foreach (Arr::wrap($listeners) as $listener) {
233	                    if (is_string($listener) && method_exists($subscriber, $listener)) {
234	                        $this->listen($event, [get_class($subscriber), $listener]);
235	
236	                        continue;
237	                    }
238	
239	                    $this->listen($event, $listener);
240	                }
241	            }
242	        }
243	    }
244	
245	    /**
246	     * Resolve the subscriber instance.
247	     *
248	     * @param  object|class-string  $subscriber
249	     * @return ($subscriber is object ? object : mixed)
250	     */
251	    protected function resolveSubscriber($subscriber)
252	    {
253	        if (is_string($subscriber)) {
254	            return $this->container->make($subscriber);
255	        }
256	
257	        return $subscriber;
258	    }
259	
260	    /**
261	     * Fire an event until the first non-null response is returned.
262	     *
263	     * @param  string|object  $event
264	     * @param  mixed  $payload
265	     * @return array|null
266	     */
267	    public function until($event, $payload = [])
268	    {
269	        return $this->dispatch($event, $payload, true);
270	    }
271	
272	    /**
273	     * Fire an event and call the listeners.
274	     *
275	     * @param  string|object  $event
276	     * @param  mixed  $payload
277	     * @param  bool  $halt
278	     * @return array|null
279	     */
280	    public function dispatch($event, $payload = [], $halt = false)
281	    {
282	        // When the given "event" is actually an object, we will assume it is an event
283	        // object, and use the class as the event name and this event itself as the
284	        // payload to the handler, which makes object-based events quite simple.
285	        [$isEventObject, $parsedEvent, $parsedPayload] = [
286	            is_object($event),
287	            ...$this->parseEventAndPayload($event, $payload),
288	        ];
289	
290	        if ($this->shouldDeferEvent($parsedEvent)) {
291	            $this->deferredEvents[] = func_get_args();
292	
293	            return null;
294	        }
295	
296	        // If the event is not intended to be dispatched unless the current database
297	        // transaction is successful, we'll register a callback which will handle
298	        // dispatching this event on the next successful DB transaction commit.
299	        if ($isEventObject &&
300	            $parsedPayload[0] instanceof ShouldDispatchAfterCommit &&
301	            ! is_null($transactions = $this->resolveTransactionManager())) {
302	            $transactions->addCallback(
303	                fn () => $this->invokeListeners($parsedEvent, $parsedPayload, $halt)
304	            );
305	
306	            return null;
307	        }
308	
309	        return $this->invokeListeners($parsedEvent, $parsedPayload, $halt);
310	    }
311	
312	    /**
313	     * Broadcast an event and call its listeners.
314	     *
315	     * @param  string|object  $event
316	     * @param  mixed  $payload
317	     * @param  bool  $halt
318	     * @return array|null
319	     */
320	    protected function invokeListeners($event, $payload, $halt = false)
321	    {
322	        if ($this->shouldBroadcast($payload)) {
323	            $this->broadcastEvent($payload[0]);
324	        }
325	
326	        $responses = [];
327	
328	        foreach ($this->getListeners($event) as $listener) {
329	            $response = $listener($event, $payload);
330	
331	            // If a response is returned from the listener and event halting is enabled
332	            // we will just return this response, and not call the rest of the event
333	            // listeners. Otherwise we will add the response on the response list.
334	            if ($halt && ! is_null($response)) {
335	                return $response;
336	            }
337	
338	            // If a boolean false is returned from a listener, we will stop propagating
339	            // the event to any further listeners down in the chain, else we keep on
340	            // looping through the listeners and firing every one in our sequence.
341	            if ($response === false) {
342	                break;
343	            }
344	
345	            $responses[] = $response;
346	        }
347	
348	        return $halt ? null : $responses;
349	    }
350	
351	    /**
352	     * Parse the given event and payload and prepare them for dispatching.
353	     *
354	     * @param  mixed  $event
355	     * @param  mixed  $payload
356	     * @return array{string, array}
357	     */
358	    protected function parseEventAndPayload($event, $payload)
359	    {
360	        if (is_object($event)) {
361	            [$payload, $event] = [[$event], get_class($event)];
362	        }
363	
364	        return [$event, Arr::wrap($payload)];
365	    }
366	
367	    /**
368	     * Determine if the payload has a broadcastable event.
369	     *
370	     * @return bool
371	     */
372	    protected function shouldBroadcast(array $payload)
373	    {
374	        return isset($payload[0]) &&
375	               $payload[0] instanceof ShouldBroadcast &&
376	               $this->broadcastWhen($payload[0]);
377	    }
378	
379	    /**
380	     * Check if the event should be broadcasted by the condition.
381	     *
382	     * @param  mixed  $event
383	     * @return bool
384	     */
385	    protected function broadcastWhen($event)
386	    {
387	        return method_exists($event, 'broadcastWhen')
388	            ? $event->broadcastWhen()
389	            : true;
390	    }
391	
392	    /**
393	     * Broadcast the given event class.
394	     *
395	     * @param  \Illuminate\Contracts\Broadcasting\ShouldBroadcast  $event
396	     * @return void
397	     */
398	    protected function broadcastEvent($event)
399	    {
400	        $this->container->make(BroadcastFactory::class)->queue($event);
401	    }
402	
403	    /**
404	     * Get all of the listeners for a given event name.
405	     *
406	     * @param  string  $eventName
407	     * @return array
408	     */
409	    public function getListeners($eventName)
410	    {
411	        $listeners = array_merge(
412	            $this->prepareListeners($eventName),
413	            $this->wildcardsCache[$eventName] ?? $this->getWildcardListeners($eventName)
414	        );
415	
416	        return class_exists($eventName, false)
417	            ? $this->addInterfaceListeners($eventName, $listeners)
418	            : $listeners;
419	    }
420	
421	    /**
422	     * Get the wildcard listeners for the event.
423	     *
424	     * @param  string  $eventName
425	     * @return array
426	     */
427	    protected function getWildcardListeners($eventName)
428	    {
429	        $wildcards = [];
430	
431	        foreach ($this->wildcards as $key => $listeners) {
432	            if (Str::is($key, $eventName)) {
433	                foreach ($listeners as $listener) {
434	                    $wildcards[] = $this->makeListener($listener, true);
435	                }
436	            }
437	        }
438	
439	        return $this->wildcardsCache[$eventName] = $wildcards;
440	    }
441	
442	    /**
443	     * Add the listeners for the event's interfaces to the given array.
444	     *
445	     * @param  string  $eventName
446	     * @return array
447	     */
448	    protected function addInterfaceListeners($eventName, array $listeners = [])
449	    {
450	        foreach (class_implements($eventName) as $interface) {
451	            if (isset($this->listeners[$interface])) {
452	                foreach ($this->prepareListeners($interface) as $names) {
453	                    $listeners = array_merge($listeners, (array) $names);
454	                }
455	            }
456	        }
457	
458	        return $listeners;
459	    }
460	
461	    /**
462	     * Prepare the listeners for a given event.
463	     *
464	     * @return \Closure[]
465	     */
466	    protected function prepareListeners(string $eventName)
467	    {
468	        $listeners = [];
469	
470	        foreach ($this->listeners[$eventName] ?? [] as $listener) {
471	            $listeners[] = $this->makeListener($listener);
472	        }
473	
474	        return $listeners;
475	    }
476	
477	    /**
478	     * Register an event listener with the dispatcher.
479	     *
480	     * @param  \Closure|string|array{class-string, string}  $listener
481	     * @param  bool  $wildcard
482	     * @return \Closure
483	     */
484	    public function makeListener($listener, $wildcard = false)
485	    {
486	        if (is_string($listener)) {
487	            return $this->createClassListener($listener, $wildcard);
488	        }
489	
490	        if (is_array($listener) && isset($listener[0]) && is_string($listener[0])) {
491	            return $this->createClassListener($listener, $wildcard);
492	        }
493	
494	        return function ($event, $payload) use ($listener, $wildcard) {
495	            if ($wildcard) {
496	                return $listener($event, $payload);
497	            }
498	
499	            return $listener(...array_values($payload));
500	        };
501	    }
502	
503	    /**
504	     * Create a class based listener using the IoC container.
505	     *
506	     * @param  string  $listener
507	     * @param  bool  $wildcard
508	     * @return \Closure
509	     */
510	    public function createClassListener($listener, $wildcard = false)
511	    {
512	        return function ($event, $payload) use ($listener, $wildcard) {
513	            if ($wildcard) {
514	                return call_user_func($this->createClassCallable($listener), $event, $payload);
515	            }
516	
517	            $callable = $this->createClassCallable($listener);
518	
519	            return $callable(...array_values($payload));
520	        };
521	    }
522	
523	    /**
524	     * Create the class based event callable.
525	     *
