670	            ? (isset($arguments[0]) ? $listener->viaConnection($arguments[0]) : $listener->viaConnection())
671	            : $this->getAttributeValue($listener, Connection::class, 'connection');
672	
673	        $connection = $this->resolveQueue()->connection(
674	            $connectionName ?? $this->resolveConnectionFromQueueRoute($listener) ?? null
675	        );
