326	    {
327	        if (! $this->container->bound(ContextRepository::class) ||
328	            ! $this->container->bound(CacheFactory::class)) {
329	            return;
330	        }
331	
332	        $context = $this->container->make(ContextRepository::class);
333	
334	        [$store, $key] = [
335	            $context->getHidden('laravel_unique_job_cache_store'),
336	            $context->getHidden('laravel_unique_job_key'),
337	        ];
338	
339	        if ($store && $key) {
