355	    {
356	        if (! isset(class_uses_recursive($class)[Batchable::class])) {
357	            return;
358	        }
359	
360	        if (! $this->container->bound(BatchRepository::class)) {
361	            return;
362	        }
363	
364	        $batchId = $job->payload()['data']['batchId'] ?? null;
365	
366	        if ((! is_string($batchId) || $batchId === '') ||
367	             ! is_string($job->uuid()) || $job->uuid() === '') {
368	            return;
