413	     *
414	     * @param  string  $uuid
415	     * @param  mixed  $command
416	     * @param  \Throwable  $e
417	     * @return void
418	     */
419	    protected function ensureFailedBatchJobIsRecorded(string $uuid, $command, $e)
420	    {
421	        if (! isset(class_uses_recursive($command)[Batchable::class])) {
422	            return;
423	        }
424	
425	        if ($batch = $command->batch()) {
426	            $batch->recordFailedJob($uuid, $e);
427	        }
428	    }
