431	     * Ensure the chained job catch callbacks are invoked.
432	     *
433	     * @param  string  $uuid
434	     * @param  mixed  $command
435	     * @param  \Throwable  $e
436	     * @return void
437	     */
438	    protected function ensureChainCatchCallbacksAreInvoked(string $uuid, $command, $e)
