208	        while (true) {
209	            // Before reserving any jobs, we will make sure this queue is not paused and
210	            // if it is we will just pause this worker for a given amount of time and
211	            // make sure we do not need to kill this worker process off completely.
212	            if (! $this->daemonShouldRun($options, $connectionName, $queue)) {
213	                [$status, $reason] = $this->pauseWorker(
214	                    $options, $lastRestart, $startTime, $jobsProcessed, $lastJobProcessedAt
215	                );
216	
217	                if (! is_null($status)) {
218	                    return $this->stop($status, $options, $reason);
219	                }
220	
221	                continue;
222	            }
223	
224	            if (isset($this->resetScope)) {
225	                ($this->resetScope)();
226	            }
