619	    /**
620	     * Mark the given job as failed if it has exceeded the maximum allowed attempts.
621	     *
622	     * This will likely be because the job previously exceeded a timeout.
623	     *
624	     * @param  string  $connectionName
625	     * @param  \Illuminate\Contracts\Queue\Job  $job
626	     * @param  int  $maxTries
627	     * @return void
628	     *
629	     * @throws \Throwable
630	     */
631	    protected function markJobAsFailedIfAlreadyExceedsMaxAttempts($connectionName, $job, $maxTries)
632	    {
633	        $maxTries = ! is_null($job->maxTries()) ? $job->maxTries() : $maxTries;
634	
635	        $retryUntil = $job->retryUntil();
636	
637	        if ($retryUntil && Carbon::now()->getTimestamp() <= $retryUntil) {
638	            return;
639	        }
640	
641	        if (! $retryUntil && ($maxTries === 0 || $job->attempts() <= $maxTries)) {
642	            return;
643	        }
644	
645	        $this->failJob($job, $e = $this->maxAttemptsExceededException($job));
