880	    protected function listenForSignals($connectionName = null, $queue = null, ?WorkerOptions $options = null)
881	    {
882	        pcntl_async_signals(true);
883	
884	        foreach ([SIGQUIT, SIGTERM, SIGINT] as $signal) {
885	            pcntl_signal($signal, function (int $signal) use ($connectionName, $queue, $options) {
886	                $this->shouldQuit = true;
