888	                $this->events->dispatch(new WorkerInterrupted($signal, $connectionName, $queue, $options));
889	
890	                $this->notifyJobOfSignal($signal);
891	            });
892	        }
893	
894	        pcntl_signal(SIGUSR2, function () use ($queue, $connectionName, $options) {
895	            $this->paused = true;
896	
897	            $this->events->dispatch(new WorkerPausing($connectionName, $queue, $options));
898	        });
899	
900	        pcntl_signal(SIGCONT, function () use ($connectionName, $queue, $options) {
901	            $this->paused = false;
902	
903	            $this->events->dispatch(new WorkerResuming($connectionName, $queue, $options));
904	        });
