        throw new Exception('Job is incomplete class: '.json_encode($command));
    }

    $lockReleased = false;

    return (new Pipeline($this->container))->send($command)
        ->through(array_merge(
            method_exists($command, 'middleware') ? $command->middleware() : [],
            $command->middleware ?? []
