        ->finally(function ($command) use (&$lockReleased) { ... })
        ->then(function ($command) use ($job, &$lockReleased) {
            if ($this->commandShouldBeUniqueUntilProcessing($command) && ...) {
                $this->ensureUniqueJobLockIsReleased($command);
                $lockReleased = true;
