}
```

This method is called internally whenever a `ShouldBroadcast` event is dispatched. It immediately delegates to `BroadcastManager::queue()`.

### Queue or Dispatch: `BroadcastManager::queue()`
**File**: `/home/bench/repos/laravel/src/Illuminate/Broadcasting/BroadcastManager.php`  
**Lines**: 188-237

This is the critical method that decides how to handle the broadcast:

```php
public function queue($event)
{
    // If ShouldBroadcastNow, dispatch immediately (synchronously)
    if ($event instanceof ShouldBroadcastNow ||
        (is_object($event) && method_exists($event, 'shouldBroadcastNow') && $event->shouldBroadcastNow())) {
        $dispatch = fn () => $this->app->make(BusDispatcherContract::class)
            ->dispatchNow(new BroadcastEvent(clone $event));  // ← Sync dispatch

        return $event instanceof ShouldRescue
            ? $this->rescue($dispatch)
            : $dispatch();
    }

    // Otherwise, queue it (async via queue system)
    $queue = match (true) {
        method_exists($event, 'broadcastQueue') => $event->broadcastQueue(),
        isset($event->broadcastQueue) => $event->broadcastQueue,
        isset($event->queue) => $event->queue,
        default => null,
    };

    if (is_null($queue)) {
        $queue = $this->getAttributeValue($event, QueueAttribute::class, 'queue')
            ?? $this->resolveQueueFromQueueRoute($event)
            ?? null;
    }

    $broadcastEvent = new BroadcastEvent(clone $event);  // ← Wrap in BroadcastEvent

    if ($event instanceof ShouldBeUnique) {
        $broadcastEvent = new UniqueBroadcastEvent(clone $event);
        if ($this->mustBeUniqueAndCannotAcquireLock($broadcastEvent)) {
            return;
        }
    }

    // Push to queue (NOT immediate)
    $push = fn () => $this->app->make('queue')
        ->connection(...)
        ->pushOn($queue, $broadcastEvent);  // ← Queued for later

    $event instanceof ShouldRescue
        ? $this->rescue($push)
        : $push();
